%[text] # 例10.5（スコアベースRED法）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2026a
%[text] ## 段数の選択（変更可能）
%[text] 事前学習済みSBDMのノイズレベル条件付き除去器 $f(\\cdot;\\sigma)$ として，
%[text] 例10.2の結合重みTNRDをノイズレベル条件付きに拡張したモデルを用いる。
%[text] トゥイーディーの公式より除去器の残差の大きさは $\\sigma$ に比例するため，
%[text] 各段の残差を $\\sigma$ でスケーリングする
%[text]  $\\mathbf{x} \\leftarrow \\mathbf{x}-\\sigma\\lambda\_s\\,\\mathbf{W}\_{a,s}^\\top\\tanh(\\mathbf{W}\_{a,s}\\mathbf{x}+\\mathbf{b}\_{a,s})$，$s=1,\\ldots,S$
%[text] とすれば，単一のネットワークで異なるノイズレベルに対応できる。
%[text] 段数 $S$（`nStages`）を増やすと除去性能が向上する（学習時間は増加）。
nStages = 1;   % 1: 単段（軽量） / 3: 多段（高性能）
%%
%[text] ## 準備
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example10_05"; %#ok<NASGU>

imgname = "msipimg05";
imgfmt  = "tiff";

rng(0)
close all
%%
%[text] ## 画像データの読込
szOrg = [96 96];
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),szOrg,'bilinear');
%%
%[text] ## 観測モデルの設定
%[text] ガウスぼかし + AWGN: $\\mathbf{v}=\\mathbf{Hx}+\\mathbf{w}$ （例10.4と同一）
sigmaK = 2.0;
blurKernel = fspecial('gaussian', 9, sigmaK);
H   = @(x)   imfilter(x, blurKernel, 'circular');
Ht  = @(x)   imfilter(x, rot90(blurKernel,2), 'circular');

sigmaW = 5/255;
V = H(X) + sigmaW * randn(size(X));
psnr_obs = psnr(V, X);
fprintf("観測画像 PSNR: %.2f dB\n", psnr_obs) %[output:8d23dd3f]
%%
%[text] ## ノイズレベル条件付きTNRD除去器の学習または読込
%[text] 事例画像（kodim01〜08，復元対象とは別）に対し，ランダムな
%[text] ノイズレベル $\\sigma\\in\[\\sigma\_{\\min},\\sigma\_{\\max}\]$ のAWGN観測
%[text] $\\mathbf{v}\_\\sigma=\\mathbf{x}+\\mathbf{w}\_\\sigma$ を毎エポック生成して
%[text] MMSE規範で全段を通して学習する（例10.2の 'tied' と同じ結合重み構造）。
sigmaMin = 2/255;
sigmaMax = 25/255;

tnrdFile = fullfile(datfolder, sprintf('example10_05_tnrd_s%d.mat', nStages));
if isfile(tnrdFile) %[output:group:20981bab]
    S = load(tnrdFile);
    prm = S.prm;
    fprintf("σ条件付きTNRD除去器(%d段)を読込: %s\n", nStages, tnrdFile) %[output:8722ba63]
else
    fprintf("σ条件付きTNRD除去器(%d段)の学習を開始します...\n", nStages)
    nExemplars = 8;
    Es = cell(1, nExemplars);
    for idx = 1:nExemplars
        exfile = fullfile(datfolder, sprintf("kodim%02d.png", idx));
        Es{idx} = imresize(im2single(rgb2gray(imread(exfile))), szOrg, 'bilinear');
    end

    P = 32; fs = 5; N = fs*fs;
    prm = struct('Wa',{cell(1,nStages)},'ba',{cell(1,nStages)}, ...
        'bs',{cell(1,nStages)},'loglam',{cell(1,nStages)});
    for s = 1:nStages
        prm.Wa{s} = dlarray(randn(fs, fs, 1, P, 'single') / sqrt(P*N));
        prm.ba{s} = dlarray(zeros(P, 1, 'single'));
        prm.bs{s} = dlarray(zeros(1, 1, 'single'));
        prm.loglam{s} = dlarray(log(single(1.0)));
    end
    lr = 1e-3; beta1=0.9; beta2=0.999; eps_a=1e-8;
    avgG = []; avgSqG = [];
    nEpochs = 1000 + 1000*nStages;
    for epoch = 1:nEpochs
        E = Es{randi(nExemplars)};
        E_dl = dlarray(E,'SSCB');
        % 対数一様分布からノイズレベルを抽出
        sigma_e = single(exp(log(sigmaMin) + (log(sigmaMax)-log(sigmaMin))*rand));
        V_dl = dlarray(E + sigma_e*randn(size(E),'single'),'SSCB');
        [~,grads] = dlfeval(@convCondTnrdLoss,prm,V_dl,E_dl,sigma_e);
        [prm,avgG,avgSqG] = adamupdate(prm,grads,avgG,avgSqG,epoch,lr,beta1,beta2,eps_a);
        if mod(epoch,500)==0
            sig_t = single(10/255);
            Vt = Es{1} + sig_t*randn(size(Es{1}),'single');
            Xh = convCondTnrdDenoise(prm,Vt,sig_t);
            fprintf("  epoch %4d: PSNR(σ=10/255)=%.2f dB\n", epoch, psnr(Xh,double(Es{1})))
        end
    end
    S = struct('prm',prm);
    save(tnrdFile, '-struct', 'S')
    fprintf("保存完了: %s\n", tnrdFile)
end %[output:group:20981bab]

% ノイズレベル σ を条件とするAWGN除去器 f(・;σ)
deawgn = @(v, sigma) convCondTnrdDenoise(prm, v, sigma);
%%
%[text] ## 除去器単体の性能確認（学習未使用画像）
Echk = imresize(im2double(rgb2gray(imread(fullfile(datfolder,'kodim09.png')))),szOrg,'bilinear');
for sig = [2 5 10 25]/255 %[output:group:921c3e03]
    rng(2)
    Vchk = Echk + sig*randn(size(Echk));
    fprintf("σ=%4.1f/255: 観測 %.2f dB → 除去 %.2f dB\n", ... %[output:36df0a28]
        sig*255, psnr(Vchk,Echk), psnr(deawgn(Vchk,sig),Echk)) %[output:36df0a28]
end %[output:group:921c3e03]
%%
%[text] ## スコアベースRED法による画像復元
%[text] 例10.4と同形の反復:
%[text]  $\\mathbf{x}^{(t+1)}\\leftarrow\\mathbf{x}^{(t)}-\\mu\\left\[\\mathbf{H}^\\top(\\mathbf{H}\\mathbf{x}^{(t)}-\\mathbf{v})+\\lambda(\\mathbf{x}^{(t)}-f(\\mathbf{x}^{(t)};\\sigma^{(t)}))\right\]$
%[text] ノイズレベル $\\sigma^{(t)}$ は事前分布の平滑化の度合いを定める調整パラメータ。
%[text] 次の5設定を比較する。
%[text] (a) 正則化なし（$\\lambda=0$），(b) 固定 $\\sigma=2/255$（観測ノイズに適合），
%[text] (c) 固定 $\\sigma=25/255$（平滑化が過大），(d) 減衰スケジュール，
%[text] (e) 除去器の入力に微小なノイズを注入する確率的な拡張
%[text] $f(\\mathbf{x}^{(t)}+\\sigma^{(t)}\\boldsymbol{\\zeta}^{(t)};\\sigma^{(t)})$
mu     = 0.5;   % ステップサイズ
lambda = 1.0;   % 正則化パラメータ
nIters = 200;

% 減衰スケジュール（対数的に減衰）
sigmaSchedule = exp(linspace(log(sigmaMax), log(sigmaMin), nIters));

labels = {'正則化なし', '固定 \sigma=2/255', '固定 \sigma=25/255', ...
    '減衰 \sigma^{(t)}', '確率的拡張'};                              % 凡例用（TeX表記）
plainLabels = {'正則化なし', '固定σ=2/255', '固定σ=25/255', ...
    '減衰σ(t)', '確率的拡張'};                                       % 表示用
lambdas = [0 lambda lambda lambda lambda];
nModes = 5;
psnrs = zeros(nIters, nModes);
xs = cell(1, nModes);

for mode = 1:nModes %[output:group:8e506229]
    rng(1)
    x_sred = V;  % 初期値: 観測画像
    for iter = 1:nIters
        switch mode
            case 2, sigma_t = sigmaMin;            % 観測ノイズに適合した固定値
            case 3, sigma_t = sigmaMax;            % 過大な固定値
            otherwise, sigma_t = sigmaSchedule(iter);
        end

        % データフィデリティ項の勾配
        grad_data = Ht(H(x_sred) - V);

        % RED正則化項の勾配: x - f(x;σ)
        if mode == 5
            % 確率的拡張: 除去器の入力にノイズを注入
            zeta = randn(size(x_sred));
            grad_reg = x_sred - deawgn(x_sred + sigma_t * zeta, sigma_t);
        else
            grad_reg = x_sred - deawgn(x_sred, sigma_t);
        end

        % GD更新
        x_sred = x_sred - mu * (grad_data + lambdas(mode) * grad_reg);
        x_sred = min(max(x_sred, 0), 1);
        psnrs(iter, mode) = psnr(x_sred, X);
    end
    xs{mode} = x_sred;
    fprintf("スコアベースRED (%s) PSNR: %.2f dB (反復数: %d)\n", ... %[output:075ad6a4]
        plainLabels{mode}, psnrs(nIters, mode), nIters) %[output:075ad6a4]
end %[output:group:8e506229]
%%
%[text] ## ウィナーフィルタによる比較
H_freq = psf2otf(blurKernel, szOrg);
snr_est = 1 / sigmaW^2;
X_wiener = real(ifft2(fft2(V) .* conj(H_freq) ./ (abs(H_freq).^2 + 1/snr_est)));
X_wiener = min(max(X_wiener, 0), 1);
psnr_wiener = psnr(X_wiener, X);
fprintf("ウィナーフィルタ PSNR: %.2f dB\n", psnr_wiener) %[output:01251a70]
%%
%[text] ## 結果の表示
fontSize = 14;

figure(1) %[output:076ecaad]
subplot(2,4,1); imshow(X);       title('原画像','FontSize',11) %[output:076ecaad]
subplot(2,4,2); imshow(V);       title(sprintf('観測 (%.2f dB)',psnr_obs),'FontSize',11) %[output:076ecaad]
subplot(2,4,3); imshow(X_wiener);title(sprintf('ウィナー (%.2f dB)',psnr_wiener),'FontSize',11) %[output:076ecaad]
subplot(2,4,4); imshow(xs{1});   title(sprintf('正則化なし (%.2f dB)',psnrs(nIters,1)),'FontSize',11) %[output:076ecaad]
subplot(2,4,5); imshow(xs{2});   title(sprintf('固定\\sigma=2/255 (%.2f dB)',psnrs(nIters,2)),'FontSize',11) %[output:076ecaad]
subplot(2,4,6); imshow(xs{3});   title(sprintf('固定\\sigma=25/255 (%.2f dB)',psnrs(nIters,3)),'FontSize',11) %[output:076ecaad]
subplot(2,4,7); imshow(xs{4});   title(sprintf('減衰\\sigma^{(t)} (%.2f dB)',psnrs(nIters,4)),'FontSize',11) %[output:076ecaad]
subplot(2,4,8); imshow(xs{5});   title(sprintf('確率的拡張 (%.2f dB)',psnrs(nIters,5)),'FontSize',11) %[output:076ecaad]
imwrite(xs{3}, fullfile(resfolder,'fig10-05a_verify.png'))

figure(2) %[output:23aa4c09]
styles = {'k-', 'k--', 'k-', 'k--', 'k:'};
widths = [0.8 0.8 1.8 1.8 1.2];
hold on %[output:23aa4c09]
for mode = 1:nModes
    plot(1:nIters, psnrs(:,mode), styles{mode}, 'LineWidth', widths(mode)) %[output:23aa4c09]
end
hold off %[output:23aa4c09]
xlabel('反復数','FontSize',fontSize) %[output:23aa4c09]
ylabel('PSNR [dB]','FontSize',fontSize) %[output:23aa4c09]
yline(psnr_wiener,'k-.','LineWidth',1.0,'Label','ウィナーフィルタ') %[output:23aa4c09]
legend(labels{:}, 'Location', 'southeast') %[output:23aa4c09]
title(sprintf('スコアベースRED法: PSNRの収束（%d段TNRD）',nStages)) %[output:23aa4c09]
set(gca,'FontSize',fontSize) %[output:23aa4c09]
%%
%[text] ## 【関数定義】
%[text] 多段TNRDの順伝播: 各段で $\\mathbf{x} \\leftarrow \\mathbf{x}-\\sigma\\lambda\_s\\,\\mathbf{W}\_{a,s}^\\top\\tanh(\\mathbf{W}\_{a,s}\\mathbf{x}+\\mathbf{b}\_{a,s})$

function Xh = convCondTnrdForward(prm, V, sigma)
Xh = V;
for s = 1:numel(prm.Wa)
    Y  = dlconv(Xh, prm.Wa{s}, prm.ba{s}, 'Padding','same');
    G  = dltranspconv(tanh(Y), prm.Wa{s}, prm.bs{s}, 'Cropping','same');
    Xh = Xh - sigma*exp(prm.loglam{s})*G;
end
end

function [loss, grads] = convCondTnrdLoss(prm, V, X_star, sigma)
Xh = convCondTnrdForward(prm, V, sigma);
loss = mean((X_star - Xh).^2, 'all');
grads = dlgradient(loss, prm);
end

function x_out = convCondTnrdDenoise(prm, x_in, sigma)
V_dl  = dlarray(single(x_in),'SSCB');
Xh    = convCondTnrdForward(prm, V_dl, single(sigma));
x_out = min(max(double(extractdata(Xh)),0),1);
end

